import{_ as e,o as r,c as l,a2 as t}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"跨账号划转","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"transfers-and-fx/cross-account-transfer.md","filePath":"zh-CN/transfers-and-fx/cross-account-transfer.md"}'),i={name:"transfers-and-fx/cross-account-transfer.md"};function o(n,a,s,h,c,d){return r(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="跨账号划转" tabindex="-1">跨账号划转 <a class="header-anchor" href="#跨账号划转" aria-label="Permalink to &quot;跨账号划转&quot;">​</a></h1><p>同一长桥 ID 跨券商和不同 ID 跨券商资金划转的授权、操作、到账时间及限额。</p><h2 id="同一账号跨券商划转" tabindex="-1">同一账号跨券商划转 <a class="header-anchor" href="#同一账号跨券商划转" aria-label="Permalink to &quot;同一账号跨券商划转&quot;">​</a></h2><p>适用于同一长桥 ID 下同时拥有长桥香港账户和长桥新加坡账户的用户，可在两个券商账户之间进行资金划拨。</p><h3 id="授权流程" tabindex="-1">授权流程 <a class="header-anchor" href="#授权流程" aria-label="Permalink to &quot;授权流程&quot;">​</a></h3><p>首次使用需先完成授权：</p><ol><li>长桥 App - 资产 - 全部功能 - 资金划转 - 跨券商账户资金划转</li><li>发起授权申请，阅读授权协议（需滑到最底部），确认个人信息后点击「立即授权」</li><li>授权成功后即可进行资金划转</li></ol><p>如系统检测到香港和新加坡账户信息不一致，需人工审核，等待授权结果即可。如两边证件不一致，需在对应柜台提交更新证件。</p><h3 id="划转操作" tabindex="-1">划转操作 <a class="header-anchor" href="#划转操作" aria-label="Permalink to &quot;划转操作&quot;">​</a></h3><p>授权成功后，选择转入账户和转出账户，填写划转金额，确认信息后提交。</p><ul><li>H 开头的证券账号为长桥香港账户</li><li>SG 开头的证券账号为长桥新加坡账户</li></ul><h3 id="到账时间" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间" aria-label="Permalink to &quot;到账时间&quot;">​</a></h3><p>预计 1-2 个工作日到账。由于香港和新加坡当地节假日不同，具体工作日以转入券商所在地为准。</p><h3 id="划转限额" tabindex="-1">划转限额 <a class="header-anchor" href="#划转限额" aria-label="Permalink to &quot;划转限额&quot;">​</a></h3><p>单笔转账融资划转金额不超过 10 万 HKD。</p><h3 id="撤销划转" tabindex="-1">撤销划转 <a class="header-anchor" href="#撤销划转" aria-label="Permalink to &quot;撤销划转&quot;">​</a></h3><p>资金划转处于「已提交」状态时，可在划转记录详情页点击撤销。</p><h3 id="进度查询与余额通限制" tabindex="-1">进度查询与余额通限制 <a class="header-anchor" href="#进度查询与余额通限制" aria-label="Permalink to &quot;进度查询与余额通限制&quot;">​</a></h3><ul><li>划转成功后会收到推送和邮件通知，也可在划转记录详情页查看进度</li><li>如账户资金在余额通中，资金划转额度会显示为 0，需先赎回余额通或等待资金交收完毕</li></ul><hr><h2 id="非同一账号跨券商划转" tabindex="-1">非同一账号跨券商划转 <a class="header-anchor" href="#非同一账号跨券商划转" aria-label="Permalink to &quot;非同一账号跨券商划转&quot;">​</a></h2><p>适用于在两个不同长桥 ID 下分别拥有长桥香港账户和长桥新加坡账户的用户。</p><p>例如：长桥香港账户的长桥 ID 为 3456789，长桥新加坡账户的长桥 ID 为 3987654。两个账户需分别在不同设备/APP 下登录，不能在 APP 资产页面直接切换。</p><h3 id="操作流程" tabindex="-1">操作流程 <a class="header-anchor" href="#操作流程" aria-label="Permalink to &quot;操作流程&quot;">​</a></h3><ol><li>联系客服申请人工预关联，提供两个账户的证券 ID 信息（无需提供证件信息）</li><li>预关联完成后，在 APP 内提交授权申请</li><li>授权申请提交后需人工审核，审核通过后即可进行资金划转</li><li>在长桥香港发起的划转需用香港账号确认，在长桥新加坡发起的需用新加坡账号确认</li></ol>',25)])])}const f=e(i,[["render",o]]);export{p as __pageData,f as default};
